INSERT INTO "products" ("id", "name", "brand", "description", "created_at") VALUES
(1, 'Dell XPS 13 Plus', 'Dell', 'Laptop ultrabook', '2026-03-24 15:04:46'),
(2, 'MacBook Air M4', 'Apple', 'MacBook Air M4 mỏng nhẹ', '2026-03-24 15:04:46'),
(3, 'Asus ROG STRIX G16', 'Asus', 'Asus ROG STRIX G16 là laptop gaming mạnh mẽ với card đồ họa NVIDIA RTX 4070, màn hình 165Hz, hệ thống tản nhiệt Tri-Fan, đáp ứng mọi tựa game AAA ở chất lượng cao.', '2026-03-24 15:04:46'),
(4, 'Dell Latitude 7440', 'Dell', 'Dell Latitude 7440', '2026-03-24 15:04:46'),
(5, 'Lenovo ThinkPad X1 Carbon Gen 12', 'Lenovo', 'ThinkPad X1 Carbon Gen 12 nổi tiếng với độ bền chuẩn MIL-SPEC, bàn phím ThinkPad huyền thoại, bảo mật vân tay và IR, lý tưởng cho chuyên gia và nhà quản lý.', '2026-03-24 15:04:46'),
(6, 'HP Spectre x360 14', 'HP', 'HP Spectre x360 14 là laptop 2-in-1 cao cấp với màn hình OLED cảm ứng, thiết kế xoay gập 360 độ, hỗ trợ bút cảm ứng, phù hợp cho sáng tạo và thuyết trình.', '2026-03-24 15:04:46'),
(7, 'Asus Zenbook 14 OLED', 'Asus', 'Asus Zenbook 14 OLED sở hữu màn hình OLED 2.8K 120Hz cho màu sắc chính xác, thiết kế mỏng nhẹ sang trọng, pin trâu, phù hợp cho nhà thiết kế và dân văn phòng.', '2026-03-24 15:04:46'),
(8, 'Acer Swift X 14', 'Acer', 'Acer Swift X 14 kết hợp CPU Intel Core Ultra và GPU NVIDIA RTX 4070 trong thiết kế mỏng nhẹ, lý tưởng cho công việc đồ họa, render và lập trình hiệu năng cao.', '2026-03-24 15:04:46'),
(9, 'MSI Stealth 16 AI Studio', 'MSI', 'MSI Stealth 16 AI Studio là laptop sáng tạo hàng đầu với chip Intel Core Ultra 9, RTX 4080, màn hình QHD+ 240Hz, đáp ứng các tác vụ AI, render 3D và gaming đỉnh cao.', '2026-03-24 15:04:46'),
(10, 'Lenovo Legion Pro 5', 'Lenovo', 'Lenovo Legion Pro 5', '2026-03-24 15:04:46'),
(15, 'Asus Zenbook S14', 'Asus', 'Asus Zenbook S14 OLED UX5406SA-PV140WS là chiếc laptop văn phòng cao cấp', '2026-03-31 14:08:16'),
(11, 'Apple MacBook Pro 14 M4 Pro', 'Apple', 'MacBook Pro 14 M4 Pro với chip M4 Pro 14 nhân, màn hình Liquid Retina XDR ProMotion 120Hz, hỗ trợ Thunderbolt 5, là công cụ sáng tạo chuyên nghiệp đỉnh cao.', '2026-03-24 15:04:46'),
(12, 'Dell XPS 15', 'Dell', 'Dell XPS 15 sở hữu màn hình OLED 3.5K sắc nét, card RTX 4060, thiết kế nhôm cao cấp, phù hợp cho nhà thiết kế đồ họa và dân sáng tạo nội dung.', '2026-03-24 15:04:46'),
(13, 'HP Omen 16', 'HP', 'HP Omen 16 là laptop gaming mạnh mẽ với Intel Core i7-14700HX, RTX 4070, màn hình 165Hz, hệ thống tản nhiệt Omen Tempest, đáp ứng gaming cạnh tranh cao.', '2026-03-24 15:04:46'),
(14, 'Acer Predator Helios Neo 16', 'Acer', 'Acer Predator Helios Neo 16 mang sức mạnh gaming với Intel Core i7-14700HX, RTX 4070, màn hình 165Hz, hệ thống tản nhiệt AeroBlade 3D, giá cạnh tranh trong phân khúc gaming.', '2026-03-24 15:04:46');

